CREATE TABLE IF NOT EXISTS "ai_model_call_log" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "user_id" bigint NULL DEFAULT NULL,
    "platform" varchar(32) NOT NULL,
    "model_id" bigint NULL DEFAULT NULL,
    "model" varchar(64) NOT NULL,
    "api_key_id" bigint NULL DEFAULT NULL,
    "biz_type" varchar(32) NOT NULL,
    "biz_id" bigint NOT NULL,
    "conversation_id" bigint NULL DEFAULT NULL,
    "trace_id" varchar(64) NULL DEFAULT NULL,
    "request_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "response_time" datetime NULL DEFAULT NULL,
    "duration_ms" int NULL DEFAULT NULL,
    "status" varchar(16) NOT NULL,
    "error_message" varchar(1024) NULL DEFAULT NULL,
    "request_id" varchar(128) NULL DEFAULT NULL,
    "prompt_tokens" int NULL DEFAULT NULL,
    "completion_tokens" int NULL DEFAULT NULL,
    "total_tokens" int NULL DEFAULT NULL,
    "cached_tokens" int NULL DEFAULT NULL,
    "reasoning_tokens" int NULL DEFAULT NULL,
    "token_source" varchar(16) NULL DEFAULT NULL,
    "currency" varchar(8) NOT NULL DEFAULT 'CNY',
    "price_in_per_1m" bigint NOT NULL DEFAULT 0,
    "price_cached_per_1m" bigint NOT NULL DEFAULT 0,
    "price_out_per_1m" bigint NOT NULL DEFAULT 0,
    "price_reasoning_per_1m" bigint NOT NULL DEFAULT 0,
    "cost_amount" bigint NOT NULL DEFAULT 0,
    "blocked" bit NOT NULL DEFAULT FALSE,
    "creator" varchar(64) NULL DEFAULT '',
    "create_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) NULL DEFAULT '',
    "update_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT 0,
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "ai_model_pricing" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "model_id" bigint NOT NULL,
    "currency" varchar(8) NOT NULL DEFAULT 'CNY',
    "price_in_per_1m" bigint NOT NULL DEFAULT 0,
    "price_cached_per_1m" bigint NOT NULL DEFAULT 0,
    "price_out_per_1m" bigint NOT NULL DEFAULT 0,
    "price_reasoning_per_1m" bigint NOT NULL DEFAULT 0,
    "strategy_type" varchar(32) NOT NULL DEFAULT 'DEFAULT',
    "strategy_config" text NULL,
    "status" tinyint NOT NULL,
    "creator" varchar(64) NULL DEFAULT '',
    "create_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) NULL DEFAULT '',
    "update_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT 0,
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "ai_budget_config" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "user_id" bigint NOT NULL DEFAULT 0,
    "period_type" varchar(16) NOT NULL,
    "currency" varchar(8) NOT NULL DEFAULT 'CNY',
    "budget_amount" bigint NOT NULL DEFAULT 0,
    "alert_thresholds" varchar(64) NULL DEFAULT NULL,
    "status" tinyint NOT NULL,
    "creator" varchar(64) NULL DEFAULT '',
    "create_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) NULL DEFAULT '',
    "update_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT 0,
    PRIMARY KEY ("id"),
    UNIQUE KEY "uk_budget_cfg_tenant_user_period" ("tenant_id", "user_id", "period_type")
);

CREATE TABLE IF NOT EXISTS "ai_budget_usage" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "user_id" bigint NOT NULL DEFAULT 0,
    "period_start_time" datetime NOT NULL,
    "currency" varchar(8) NOT NULL DEFAULT 'CNY',
    "used_amount" bigint NOT NULL DEFAULT 0,
    "version" int NOT NULL DEFAULT 0,
    "creator" varchar(64) NULL DEFAULT '',
    "create_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) NULL DEFAULT '',
    "update_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT 0,
    PRIMARY KEY ("id"),
    UNIQUE KEY "uk_user_period_tenant" ("user_id", "period_start_time", "tenant_id")
);

CREATE TABLE IF NOT EXISTS "ai_budget_log" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "user_id" bigint NOT NULL DEFAULT 0,
    "event_type" varchar(32) NOT NULL,
    "period_start_time" datetime NOT NULL,
    "currency" varchar(8) NOT NULL DEFAULT 'CNY',
    "budget_amount" bigint NOT NULL DEFAULT 0,
    "used_amount" bigint NOT NULL DEFAULT 0,
    "delta_amount" bigint NULL DEFAULT NULL,
    "request_biz_type" varchar(32) NULL DEFAULT NULL,
    "request_biz_id" bigint NULL DEFAULT NULL,
    "message" varchar(1024) NULL DEFAULT NULL,
    "creator" varchar(64) NULL DEFAULT '',
    "create_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) NULL DEFAULT '',
    "update_time" datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT 0,
    PRIMARY KEY ("id")
);
